// src/components/Gallery.jsx
import React, { useState, useRef } from 'react';

const Gallery = () => {
  const [images, setImages] = useState([]);
  const fileInputRef = useRef(null);
  
  // Sample gallery images (would typically come from a database)
  const galleryImages = [
    'https://images.unsplash.com/photo-1504674900247-0877df9cc836?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1546069901-ba9599a7e63c?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1565958011703-44f9829ba187?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1476224203421-9ac39bcb3327?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80',
    'https://images.unsplash.com/photo-1504754524776-8f4f37790ca0?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=800&q=80'
  ];

  const handleImageUpload = (e) => {
    const files = Array.from(e.target.files);
    if (files.length > 0) {
      const newImages = files.map(file => URL.createObjectURL(file));
      setImages([...images, ...newImages]);
    }
  };

  const triggerFileInput = () => {
    fileInputRef.current.click();
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>BUKANI MAMA TOTO GALLERY</h1>
        <p style={styles.subtitle}>Explore our journey through images of empowerment, sustainability, and community development</p>
      </div>
      
      <div style={styles.uploadContainer}>
        <button style={styles.uploadButton} onClick={triggerFileInput}>
          Upload Images
        </button>
        <input
          type="file"
          ref={fileInputRef}
          accept="image/*"
          onChange={handleImageUpload}
          style={{ display: 'none' }}
          multiple
        />
        <p style={styles.uploadHint}>Upload images to share with our community (Max 10 images)</p>
      </div>
      
      <div style={styles.galleryGrid}>
        {[...galleryImages, ...images].map((img, index) => (
          <div key={index} style={styles.galleryItem}>
            <img 
              src={img} 
              alt={`Gallery item ${index + 1}`} 
              style={styles.image}
              loading="lazy"
            />
            <div style={styles.imageOverlay}>
              <span style={styles.imageTitle}>Project #{index + 1}</span>
            </div>
          </div>
        ))}
      </div>
      
      {images.length === 0 && galleryImages.length === 0 && (
        <div style={styles.emptyState}>
          <div style={styles.emptyIcon}>📷</div>
          <h3 style={styles.emptyTitle}>No Images Yet</h3>
          <p style={styles.emptyText}>Be the first to upload images showcasing our initiatives</p>
        </div>
      )}
    </div>
  );
};

// Styles for the gallery component
const styles = {
  container: {
    padding: '20px',
    maxWidth: '1400px',
    margin: '0 auto',
    backgroundColor: '#f8f9fa',
    minHeight: '100vh',
  },
  header: {
    textAlign: 'center',
    margin: '40px 0',
    padding: '20px',
  },
  title: {
    color: '#1a936f',
    fontSize: '2.5rem',
    fontWeight: '700',
    marginBottom: '15px',
  },
  subtitle: {
    color: '#6c757d',
    fontSize: '1.1rem',
    maxWidth: '700px',
    margin: '0 auto',
    lineHeight: '1.6',
  },
  uploadContainer: {
    backgroundColor: 'white',
    borderRadius: '12px',
    padding: '30px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
    margin: '30px 0',
    textAlign: 'center',
  },
  uploadButton: {
    backgroundColor: '#1a936f',
    color: 'white',
    border: 'none',
    padding: '12px 30px',
    fontSize: '1rem',
    fontWeight: '600',
    borderRadius: '50px',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    marginBottom: '15px',
    boxShadow: '0 4px 10px rgba(26, 147, 111, 0.3)',
  },
  uploadHint: {
    color: '#6c757d',
    fontSize: '0.9rem',
    margin: '0',
  },
  galleryGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
    gap: '25px',
    marginTop: '40px',
  },
  galleryItem: {
    position: 'relative',
    borderRadius: '12px',
    overflow: 'hidden',
    boxShadow: '0 5px 15px rgba(0,0,0,0.08)',
    transition: 'transform 0.3s ease, box-shadow 0.3s ease',
    height: '280px',
    cursor: 'pointer',
  },
  image: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    display: 'block',
    transition: 'transform 0.5s ease',
  },
  imageOverlay: {
    position: 'absolute',
    bottom: '0',
    left: '0',
    right: '0',
    background: 'linear-gradient(transparent, rgba(0,0,0,0.7))',
    padding: '20px',
    color: 'white',
    opacity: '0',
    transition: 'opacity 0.3s ease',
  },
  imageTitle: {
    fontSize: '1.1rem',
    fontWeight: '600',
  },
  emptyState: {
    textAlign: 'center',
    padding: '60px 20px',
    backgroundColor: 'white',
    borderRadius: '12px',
    margin: '40px 0',
    boxShadow: '0 4px 12px rgba(0,0,0,0.05)',
  },
  emptyIcon: {
    fontSize: '4rem',
    marginBottom: '20px',
    color: '#1a936f',
  },
  emptyTitle: {
    color: '#343a40',
    fontSize: '1.8rem',
    marginBottom: '15px',
  },
  emptyText: {
    color: '#6c757d',
    fontSize: '1.1rem',
    maxWidth: '500px',
    margin: '0 auto',
    lineHeight: '1.6',
  },
};

// Add hover effects
const addHoverStyles = `
  .gallery-item:hover {
    transform: translateY(-8px);
    box-shadow: 0 12px 20px rgba(0,0,0,0.15);
  }
  
  .gallery-item:hover .image-overlay {
    opacity: 1;
  }
  
  .gallery-item:hover img {
    transform: scale(1.05);
  }
  
  .upload-button:hover {
    background: #16825f;
    transform: translateY(-3px);
    box-shadow: 0 6px 15px rgba(26, 147, 111, 0.4);
  }
`;

export default Gallery;
